(() => {
  // 1. ✅ Check renewal_status UND renewed_booking_date
  const renewalStatus = (currentRow.renewal_status ?? "").toString().trim().toLowerCase();
  const renewedBookingDate = (currentRow.renewed_booking_date ?? "").toString().trim();

  const isRenewed = 
    renewalStatus && 
    renewalStatus !== "" && 
    renewalStatus !== "not_renewed" &&
    renewedBookingDate &&
    renewedBookingDate !== "";

  if (isRenewed) {
    return "#13734b"; // Closed Won (Google Sheets Dunkelgrün)
  }

