      item.opp_id === currentRow.opportunity_id &&
      item.risk_status !== "Closed Won"  // ✅ Manuelle Closed Won rausfiltern!
    )
    .sort((a, b) => new Date(b.submit_timestamp) - new Date(a.submit_timestamp));

