{{(() => { const tableData = Renewal_List.processedTableData || []; return tableData.length > 0 ? tableData.map((currentRow, currentIndex) => (
  (() => {
    // ✅ Check renewal_status (nicht leer, nicht "not_renewed")
    const renewalStatus = (currentRow.renewal_status ?? "").toString().trim().toLowerCase();
    const isRenewed = renewalStatus && renewalStatus !== "" && renewalStatus !== "not_renewed";

    if (isRenewed) {
      return "✅";
    }

    // 🆕 Check if Renewal Lost - keine Updates nötig
    const allUpdates = GetCurrentRiskStatus.data || [];
    const hasRenewalLost = allUpdates.some(
      r => r.opp_id === currentRow["opportunity_id"] && r.risk_status === "Renewal Lost"
    );

    if (hasRenewalLost) {
      return ""; // Keine Reminder für Renewal Lost
    }

    const expiry = moment(currentRow["contract_expired_date"]);
    const today = moment();

    const getBusinessDays = (startDate, endDate) => {
      let count = 0;
      let current = startDate.clone();

      while (current.isSameOrBefore(endDate, 'day')) {
        const dayOfWeek = current.day();
        if (dayOfWeek !== 0 && dayOfWeek !== 6) {
          count++;
        }
        current.add(1, 'day');
      }

      return count;
    };

    const cedMonth = expiry.clone().startOf('month');
    const cohortIntakeDate = cedMonth.clone().subtract(6, 'months').date(1);

    if (today.isBefore(cohortIntakeDate, 'day')) {
      return "";
    }

    // ✅ Hole nur manuelle Updates (OHNE Closed Won)
    const filteredUpdates = allUpdates.filter(
      r => r.opp_id === currentRow["opportunity_id"] && r.risk_status !== "Closed Won"
    );

    const lastUpdate = filteredUpdates.length > 0 ? filteredUpdates[0] : null;
    const lastSubmit = lastUpdate ? moment(lastUpdate.submit_timestamp) : null;
    const isInitialAssessment = !lastSubmit;

    if (isInitialAssessment) {
      const gracePeriodEnd = cohortIntakeDate.clone().add(5, 'days');

      if (today.isSameOrBefore(gracePeriodEnd, 'day')) {
        return "🔔 Update";
      }

      const overdueDays = getBusinessDays(gracePeriodEnd.clone().add(1, 'day'), today);

      if (overdueDays <= 3) {
        return `🔔 ${overdueDays}d overdue`;
      } else {
        return `⚠️ ${overdueDays}d overdue`;
      }
    } else {
      const daysLeft = expiry.diff(today, 'days');
      const interval = daysLeft >= 90 ? 30 : 14;
      const nextDue = lastSubmit.clone().add(interval, 'days');

      if (today.isBefore(nextDue, 'day')) {
        return "";
      }

      if (today.isSame(nextDue, 'day')) {
        return "🔔 Update";
      }

      const overdueDays = getBusinessDays(nextDue.clone().add(1, 'day'), today);

      if (overdueDays <= 3) {
        return `🔔 ${overdueDays}d overdue`;
      } else {
        return `⚠️ ${overdueDays}d overdue`;
      }
    }
  })()
