  const renewalStatus = (currentRow.renewal_status ?? "").toString().trim().toLowerCase();
  const renewedBookingDate = (currentRow.renewed_booking_date ?? "").toString().trim();

  const isClosedWon = 
    renewalStatus && 
    renewalStatus !== "" && 
    renewalStatus !== "not_renewed" &&
    renewedBookingDate &&
    renewedBookingDate !== "";

  // ====== SCHRITT 3: Erstelle Display-Array ======
  let displayData = [];

  if (isClosedWon) {
    // ✅ Grüner Bubble ganz links (automatisch)
    displayData.push({
      risk_status: "Closed Won",
      submit_timestamp: renewedBookingDate,
      isVirtual: true
    });
    // Füge die letzten 3 manuellen Updates hinzu (ohne Closed Won)
    displayData.push(...manualUpdates.slice(0, 3));
  } else {
    // ❌ Kein Closed Won → nur die letzten 4 manuellen Updates
    displayData = manualUpdates.slice(0, 4);
  }

  // ====== SCHRITT 4: Farb-Mapping ======
  const statusColor = (status) => {
    switch (status) {
      case "At Risk": return "#e53935";       // rot
      case "Low Risk": return "#9ccc65";      // hellgrün
      case "Closed Won": return "#2E7D32";    // dunkelgrün
      case "Renewal Lost": return "#800020";  // dunkelrot
      case "To Assess": return "#ededed";     // grau
      default: return "#ededed";              // hellgrau
    }
  };

  // ====== SCHRITT 5: Trend-Berechnung ======
  const getTrend = () => {
    // ✅ Nur Pfeil ↑ wenn automatischer Closed Won UND vorheriger Status war At Risk/Renewal Lost/Low Risk
    if (isClosedWon && manualUpdates.length > 0) {
      const previousStatus = manualUpdates[0]?.risk_status;
      if (previousStatus === "At Risk" || 
          previousStatus === "Renewal Lost" || 
          previousStatus === "Low Risk") {
        return "↑";
      }
    }

    // Für normale manuelle Updates (ohne automatischen Closed Won)
    if (!isClosedWon && displayData.length >= 2) {
      const statusValues = { 
        "Low Risk": 3, 
        "At Risk": 2, 
        "Renewal Lost": 1,
        "To Assess": 0
      };

      const current = statusValues[displayData[0]?.risk_status] || 0;
      const previous = statusValues[displayData[1]?.risk_status] || 0;

      if (current > previous) return "↑";
      if (current < previous) return "↓";
      return "→";
    }

    return ""; // Kein Pfeil
  };

  const trend = getTrend();

  // ====== SCHRITT 6: HTML Rendering ======
  const dotSize = 12;
  const dotGap = 6;
  const lineHeight = 18;

  const dots = [];
  for (let i = 0; i < 4; i++) {
    const item = displayData[i];
    const color = item ? statusColor(item.risk_status) : "#ededed";
    const title = item 
      ? `${item.risk_status}${item.isVirtual ? " (Auto)" : ""}` 
      : "No data";

    dots.push(
      `<span
         title="${title}"
         style="
           display:inline-block;
           width:${dotSize}px;
           height:${dotSize}px;
           border-radius:50%;
           background:${color};
           margin-left:${i === 0 ? 0 : dotGap}px;
           vertical-align:middle;
         ">
       </span>`
    );
  }

  return `
    <div style="
      display:flex;
      align-items:center;
      width:100%;
      height:${lineHeight}px;
      line-height:${lineHeight}px;
      font-size:12px;
    ">
      <span style="flex:0 0 auto; text-align:left; min-width:1.2em;">${trend}</span>
      <span style="flex:1 1 auto; text-align:right; height:100%; line-height:${lineHeight}px;">
        ${dots.join("")}
      </span>
    </div>
  `;
})()
)) : 
