tableData:
{{ 
  renewal_management.data.filter(row => {
    const permanentlyBlockedAccountIds = [
      "001W7000001HK6bIAG"    // immer blockiert
    ];

    const temporarilyBlockedAccountIds = [
      "0011v00002C9lY4AAJ"    // erst ab 01.07.2026 sichtbar
    ];

    const blockedOpportunityIds = [
      "006W7000007nJ2HIAU",
      "006W700000BqIYoIAN",
      "006W7000009y09dIAA"
    ];

    const visibilityStart = moment("2026-07-01");

    // Block specific opportunities always
    if (blockedOpportunityIds.includes(row.opportunity_id)) {
      return false;
    }

    // Block permanently blocked accounts ALWAYS
    if (permanentlyBlockedAccountIds.includes(row.account_id)) {
      return false;
    }

    // Block temporarily blocked accounts UNTIL 01.07.2026
    if (temporarilyBlockedAccountIds.includes(row.account_id)) {
      if (moment() < visibilityStart) {
        return false;
      }
    }

    // everything else stays
    return true;
  })
}}
